const text = $input.item.json.message.text || "";
// Regex matches /command target extra (ignores spaces)
const match = text.match(/^\/([a-zA-Z0-9_]+)(?:\s+(.*))?/);

let command = "unknown";
let target = "";
let extra = "";

if (match) {
    command = match[1].toLowerCase();
    const args = (match[2] || "").trim();
    if (args) {
        const parts = args.split(/\s+/);
        target = parts[0];

        // Normalize MAC address to uppercase to prevent DB duplicates
        if (/^([0-9A-Fa-f]{2}[:-]){5}([0-9A-Fa-f]{2})$/i.test(target)) {
            target = target.toUpperCase();
        }

        extra = parts.slice(1).join(" ");
    }
}

return [{ json: { command, target, extra, original_text: text } }];

const parseData = $node["Parse Message"].json;
const target = parseData.target;
const command = parseData.command;

if (!target) {
    return [{ json: { resolved: false, reason: `⚠️ Please specify a target for /${command}.\n\nExample: /${command} MyPC` } }];
}

const devices = $input.all().map(i => i.json);

// Regex patterns for raw MAC and IP detection
const isMac = /^([0-9A-Fa-f]{2}[:-]){5}([0-9A-Fa-f]{2})$/i.test(target);
const isIp = /^(?:[0-9]{1,3}\.){3}[0-9]{1,3}$/.test(target);

let mac = isMac ? target : null;
let ip = isIp ? target : null;

if (isMac) {
    // Try to find the corresponding IP in the DB
    const found = devices.find(d => d.mac && d.mac.toLowerCase() === target.toLowerCase());
    if (found && found.ip) ip = found.ip;
} else if (isIp) {
    // Try to find the corresponding MAC in the DB
    const found = devices.find(d => d.ip === target);
    if (found && found.mac) mac = found.mac;
} else {
    // It's an alias, search the database
    const found = devices.find(d => d.name && d.name.toLowerCase() === target.toLowerCase());
    if (found) {
        mac = found.mac;
        ip = found.ip;
    } else {
        return [{ json: { resolved: false, reason: `❌ Target '<b>${target}</b>' not found.\nPlease provide a valid MAC, IP, or saved Alias.` } }];
    }
}

// Final Command Validations
if (command === "wake" && !mac) {
    return [{ json: { resolved: false, reason: `❌ Could not resolve a MAC address for '<b>${target}</b>'. Wake-on-LAN requires a MAC.\n\n<i>Tip: Check if the device is correctly saved via /list</i>` } }];
}
if (command === "ping" && !ip) {
    return [{ json: { resolved: false, reason: `❌ Could not resolve an IP address for '<b>${target}</b>'. Ping requires an IP.\n\n<i>Tip: Try running /scan while the device is awake so the bot can learn its IP!</i>` } }];
}

return [{ json: { resolved: true, mac: mac, ip: ip, target: target, command: command } }];

const parseData = $node["Parse Message"].json;
// Default to bylastseen if no parameter is provided
const listParam = (parseData.target || "bylastseen").toLowerCase();

let devices = $input.all().map(i => i.json);

// 1. Sort the devices based on the parameter
if (listParam === "byowner") {
    devices.sort((a, b) => {
        const ownerA = a.owner || "ZZZ_Unowned"; 
        const ownerB = b.owner || "ZZZ_Unowned";
        return ownerA.localeCompare(ownerB);
    });
} else {
    // Default: Sort by last_seen descending
    devices.sort((a, b) => {
        const dateA = new Date(a.last_seen || 0);
        const dateB = new Date(b.last_seen || 0);
        return dateB - dateA;
    });
}

// 2. Build the output chunks (safe for Telegram's character limits)
const chunks = [];
let currentChunk = `📋 <b>Device List (Sorted ${listParam}):</b>\n\n`;
const MAX_LENGTH = 3900; 

for (const d of devices) {
    const name = d.name || 'Unnamed Device';
    const mac = d.mac || 'Unknown MAC';
    const vendor = d.vendor ? ` [<i>${d.vendor}</i>]` : '';
    const owner = d.owner ? ` 👤 ${d.owner}` : '';

    const line = `• ${name}${vendor}${owner} (<code>${mac}</code>)\n`;

    if (currentChunk.length + line.length > MAX_LENGTH) {
        chunks.push({ json: { text: currentChunk } });
        currentChunk = "📋 <b>Device List (Cont.):</b>\n\n" + line;
    } else {
        currentChunk += line;
    }
}

// 3. CORRECTED CHECK: Check 'devices.length' instead of 'chunks.length'
if (devices.length === 0) {
    chunks.push({ json: { text: "📋 <b>No devices found in the database.</b>" } });
} else {
    // Push whatever is left in the currentChunk bucket
    chunks.push({ json: { text: currentChunk } });
}

return chunks;

const results = [];

for (const item of $input.all()) {
    // Extract the payload
    let payload = item.json.message !== undefined ? item.json.message : item.json;

    // If n8n received it as a string, parse it
    if (typeof payload === 'string') {
        try {
            payload = JSON.parse(payload);
        } catch(e) {
            continue;
        }
    }

    // Pass the cleaned payload forward
    if (payload) {
        results.push({ json: payload });
    }
}

return results;

