const devices = $input.all().map(i => i.json);

// Configuration: How many minutes until a device is considered "Away"?
const OFFLINE_MINUTES = 60;
const thresholdTime = new Date(Date.now() - (OFFLINE_MINUTES * 60 * 1000));

const owners = {};
let hasAnyOwner = false;

// 1. Group devices by Owner and check presence
for (const d of devices) {
    if (!d.owner) continue; // Skip unowned devices for the presence dashboard

    hasAnyOwner = true;

    if (!owners[d.owner]) {
        owners[d.owner] = { isHome: false, devices: [] };
    }

    const lastSeen = new Date(d.last_seen || 0);
    const isOnline = lastSeen > thresholdTime;

    // If even one device is online, the owner is marked as Home
    if (isOnline) {
        owners[d.owner].isHome = true;
    }

    // Optional: Calculate friendly "seen X mins ago" string
    const diffMins = Math.floor((Date.now() - lastSeen.getTime()) / 60000);
    const seenText = diffMins < 1 ? "Just now" : `${diffMins}m ago`;

    owners[d.owner].devices.push({
        name: d.name || d.mac,
        isOnline: isOnline,
        seenText: seenText
    });
}

// 2. Error Logic: If no owners are set in the database
if (!hasAnyOwner) {
    return [{ json: { 
        text: "⚠️ <b>No Owners Configured</b>\n\nYou haven't assigned any devices to an owner yet in your database.\n\n<i>To use the Presence dashboard, manually add names to the 'owner' column in your Data Table for your known devices!</i>" 
    }}];
}

// 3. Format the Dashboard
let outputText = "🏠 <b>Network Presence Report</b>\n\n";

// Sort owners alphabetically
const sortedOwners = Object.keys(owners).sort();

for (const ownerName of sortedOwners) {
    const data = owners[ownerName];
    const statusIcon = data.isHome ? "🟢 HOME" : "🔴 AWAY";

    outputText += `👤 <b>${ownerName}</b>: ${statusIcon}\n`;

    // List their specific devices underneath
    for (const dev of data.devices) {
        const devIcon = dev.isOnline ? "📱" : "📴";
        outputText += `  └ ${devIcon} ${dev.name} <i>(Seen: ${dev.seenText})</i>\n`;
    }
    outputText += "\n";
}

return [{ json: { text: outputText.trim() } }];

const results = [];

for (const item of $input.all()) {
    // Extract the payload (handles differences between raw MQTT and wrapped JSON)
    let payload = item.json.message !== undefined ? item.json.message : item.json;

    // If n8n received it as a string, parse it
    if (typeof payload === 'string') {
        try {
            payload = JSON.parse(payload);
        } catch(e) {
            continue; // Skip if it's not valid JSON
        }
    }

    // Skip utility events like {"event": "scan_started"}
    if (!payload || payload.event) {
        continue;
    }

    // Normalize MAC address to uppercase to prevent DB duplicates
    if (payload.mac) {
        payload.mac = String(payload.mac).toUpperCase().trim();
    }

    results.push({ json: payload });
}

return results;

// Grab the leftover text from your main parser
const extraText = $input.item.json.extra || "";

// Split the text by spaces
const parts = extraText.trim().split(/\s+/);

// The first word is the key, everything after is the value
const key = parts[0] ? parts[0].toLowerCase() : null;
const value = parts.length > 1 ? parts.slice(1).join(" ") : null;

// Pass everything forward, adding our new clean variables
return [{ 
    json: { 
        ...$input.item.json, 
        setting_key: key, 
        setting_value: value 
    } 
}];
